  1095→
  1096→## 4.3 Run Assignment Optimizer
  1097→
  1098→### 4.3.1 Purpose
  1099→
  1100→Optimize daily train-to-route assignments for mileage balancing while respecting hard constraints (fitness, PM due, **unavailability**, **service demand**) and minimizing soft constraint penalties.
  1101→
  1102→### 4.3.2 Optimizer Service (TypeScript Wrapper)
  1103→
  1104→```typescript
  1105→interface OptimizerConfig {
  1106→  binaryPath: string;          // ./mms-optimizer
  1107→  maxSolveTimeSeconds: number; // 30
  1108→  numWorkers: number;          // 4
  1109→  timeoutMs: number;           // 60000
  1110→  fallbackEnabled: boolean;    // true
  1111→}
  1112→
  1113→class RunAssignmentOptimizer {
  1114→  private process: Subprocess | null = null;
  1115→  
  1116→  async optimize(input: OptimizerInput): Promise<OptimizerResult> {
  1117→    const startTime = Date.now();
  1118→    
  1119→    try {
  1120→      // Try C++ optimizer first
  1121→      const result = await this.runCppOptimizer(input);
  1122→      
  1123→      // Validate result
  1124→      if (result.status === 'INFEASIBLE' && this.config.fallbackEnabled) {
  1125→        this.logger.warn('C++ optimizer returned INFEASIBLE, using fallback');
  1126→        return await this.runFallbackOptimizer(input);
  1127→      }
  1128→      
  1129→      return result;
  1130→      
  1131→    } catch (error) {
  1132→      this.logger.error({ error }, 'C++ optimizer failed, using fallback');
  1133→      
  1134→      if (this.config.fallbackEnabled) {
  1135→        return await this.runFallbackOptimizer(input);
  1136→      }
  1137→      
  1138→      throw error;
  1139→    }
  1140→  }
  1141→  
  1142→  private async runCppOptimizer(input: OptimizerInput): Promise<OptimizerResult> {
  1143→    return new Promise((resolve, reject) => {
  1144→      const timeout = setTimeout(() => {
  1145→        this.process?.kill();
  1146→        reject(new Error('Optimizer timeout'));
  1147→      }, this.config.timeoutMs);
  1148→      
  1149→      this.process = Bun.spawn([this.config.binaryPath], {
  1150→        stdin: 'pipe',
  1151→        stdout: 'pipe',
  1152→        stderr: 'pipe'
  1153→      });
  1154→      
  1155→      // Write input
  1156→      const writer = this.process.stdin.getWriter();
  1157→      writer.write(new TextEncoder().encode(JSON.stringify(input) + '\n'));
  1158→      writer.close();
  1159→      
  1160→      // Read stdout (results)
  1161→      const results: any[] = [];
  1162→      const reader = this.process.stdout.getReader();
  1163→      const decoder = new TextDecoder();
  1164→      let buffer = '';
  1165→      
  1166→      const readStream = async () => {
  1167→        while (true) {
  1168→          const { done, value } = await reader.read();
  1169→          if (done) break;
  1170→          
  1171→          buffer += decoder.decode(value, { stream: true });
  1172→          const lines = buffer.split('\n');
  1173→          buffer = lines.pop() || '';
  1174→          
  1175→          for (const line of lines) {
  1176→            if (!line.trim()) continue;
  1177→            
  1178→            try {
  1179→              const msg = JSON.parse(line);
  1180→              
  1181→              if (msg.type === 'PROGRESS') {
  1182→                this.emitProgress(msg);
  1183→              } else if (msg.type === 'RESULT') {
  1184→                clearTimeout(timeout);
  1185→                resolve(this.mapResult(msg));
  1186→                return;
  1187→              }
  1188→            } catch (e) {
  1189→              this.logger.warn({ line }, 'Failed to parse optimizer output');
  1190→            }
  1191→          }
  1192→        }
  1193→      };
